// Auto-generated WAV sound data URIs
const SOUNDS = {
  tick: "data:audio/wav;base64,",
  go: "data:audio/wav;base64,",
  end: "data:audio/wav;base64,",
  done: "data:audio/wav;base64,",
};

function playSound(name) {
  const src = SOUNDS[name];
  if (!src) return;
  try {
    const a = new Audio(src);
    a.volume = 1.0;
    a.play().catch(() => {});
  } catch(e) {}
}
